import { Component, signal, computed } from '@angular/core';

@Component({
  selector: 'app-product-card',
  standalone: true,
  template: `
    <!-- Basic property interpolation -->
    <h1>{{ productName }}</h1>

    <!-- Expression: arithmetic -->
    <p>Price with tax: {{ price * 1.2 | number:'1.2-2' }}</p>

    <!-- Expression: ternary -->
    <p>Status: {{ stock > 0 ? 'In Stock' : 'Out of Stock' }}</p>

    <!-- Method call -->
    <p>Label: {{ getLabel() }}</p>

    <!-- Signal — same syntax, just call with () -->
    <p>Rating: {{ rating() }} / 5</p>

    <!-- Nested object property -->
    <p>Category: {{ product.category.name }}</p>
  `,
})
export class ProductCardComponent {
  productName = 'Angular Mastery Book';
  price       = 49.99;
  stock       = 10;
  rating      = signal(4.7);
  product     = { category: { name: 'Programming' } };

  getLabel(): string {
    return this.stock > 5 ? 'Plenty available' : 'Low stock!';
  }
}

import { Component, signal } from '@angular/core';

@Component({
  selector: 'app-image-gallery',
  standalone: true,
  template: `
    <!-- [src] and [alt] — DOM properties, not HTML attributes -->
    <img [src]="currentImage()" [alt]="imageAlt" width="400" />

    <!-- [disabled] — accepts a boolean expression -->
    <button [disabled]="isLoading()" (click)="loadNext()">
      {{ isLoading() ? 'Loading...' : 'Next Image' }}
    </button>

    <!-- [href] on an anchor -->
    <a [href]="profileUrl">View Profile</a>

    <!-- Binding to a component INPUT — same syntax! -->
    <!-- <app-badge [label]="badgeText" [count]="badgeCount" /> -->

    <!-- ❌ WRONG — this passes the string "imageUrl", not the value -->
    <!-- <img src="imageUrl" />  -->

    <!-- ✓ CORRECT — evaluates the expression -->
    <!-- <img [src]="imageUrl" /> -->
  `,
})
export class ImageGalleryComponent {
  images       = ['photo1.jpg', 'photo2.jpg', 'photo3.jpg'];
  currentIndex = signal(0);
  isLoading    = signal(false);
  imageAlt     = 'Gallery image';
  profileUrl   = 'https://example.com/profile';

  currentImage = () => this.images[this.currentIndex()];

  loadNext(): void {
    this.isLoading.set(true);
    setTimeout(() => {
      this.currentIndex.update(i => (i + 1) % this.images.length);
      this.isLoading.set(false);
    }, 500);
  }
}

import { Component, signal } from '@angular/core';

@Component({
  selector: 'app-event-demo',
  standalone: true,
  template: `
    <!-- (click) — simplest event binding -->
    <button (click)="increment()">Clicks: {{ count() }}</button>

    <!-- (click) with inline expression (ok for trivial cases) -->
    <button (click)="count.set(0)">Reset</button>

    <!-- (input) — $event is the InputEvent; .target.value is the typed text -->
    <input
      (input)="onInput($event)"
      placeholder="Type something..."
    />
    <p>You typed: {{ typed() }}</p>

    <!-- (keydown.enter) — only fires when Enter is pressed -->
    <input
      (keydown.enter)="search()"
      placeholder="Press Enter to search"
    />

    <!-- (submit) on a form — prevents full page reload -->
    <form (submit)="onSubmit($event)">
      <button type="submit">Submit</button>
    </form>

    <!-- Mouse events -->
    <div
      (mouseenter)="isHovered.set(true)"
      (mouseleave)="isHovered.set(false)"
    >
      {{ isHovered() ? 'Hovering!' : 'Hover me' }}
    </div>
  `,
})
export class EventDemoComponent {
  count    = signal(0);
  typed    = signal('');
  isHovered = signal(false);

  increment(): void {
    this.count.update(n => n + 1);
  }

  // $event is typed as Event; cast target to HTMLInputElement to access .value
  onInput(event: Event): void {
    const input = event.target as HTMLInputElement;
    this.typed.set(input.value);
  }

  search(): void {
    console.log('Searching for:', this.typed());
  }

  onSubmit(event: SubmitEvent): void {
    event.preventDefault();           // stop the browser from reloading
    console.log('Form submitted');
  }
}

import { Component, signal } from '@angular/core';

@Component({
  selector: 'app-class-style-demo',
  standalone: true,
  template: `
    <!-- ── Class Binding ─────────────────────────────────── -->

    <!-- Toggle a single class based on a boolean -->
    <button
      [class.active]="isActive()"
      (click)="isActive.update(v => !v)"
    >
      {{ isActive() ? 'Active ✓' : 'Inactive' }}
    </button>

    <!-- Toggle multiple classes -->
    <div
      [class.error]="hasError()"
      [class.warning]="hasWarning()"
      [class.success]="isSuccess()"
    >
      Status message
    </div>

    <!-- Set class from a computed string -->
    <span [class]="badgeClass()">
      {{ status() }}
    </span>

    <!-- ── Style Binding ─────────────────────────────────── -->

    <!-- Set a single CSS property -->
    <p [style.color]="textColor">Styled text</p>

    <!-- With a unit — no need to append 'px' yourself -->
    <div [style.font-size.px]="fontSize()">Resizable text</div>

    <!-- Progress bar: width as a percentage -->
    <div class="progress-bar">
      <div [style.width.%]="progress()"
           [style.background-color]="progressColor()"
           class="progress-fill">
      </div>
    </div>
  `,
})
export class ClassStyleDemoComponent {
  isActive   = signal(false);
  hasError   = signal(true);
  hasWarning = signal(false);
  isSuccess  = signal(false);
  status     = signal<'online' | 'offline' | 'busy'>('online');
  fontSize   = signal(16);
  progress   = signal(65);
  textColor  = '#DD0031';

  badgeClass = () => ({
    'badge': true,
    'badge-success': this.status() === 'online',
    'badge-danger':  this.status() === 'offline',
    'badge-warning': this.status() === 'busy',
  });

  progressColor = () =>
    this.progress() < 33 ? '#ef4444' :
    this.progress() < 66 ? '#f59e0b' : '#22c55e';
}

import { Component } from '@angular/core';

@Component({
  selector: 'app-template-ref-demo',
  standalone: true,
  template: `
    <!-- #searchInput = reference to the <input> HTMLElement -->
    <input #searchInput type="text" placeholder="Search..." />

    <!-- Use the reference inline — no class property needed! -->
    <button (click)="search(searchInput.value)">Search</button>
    <button (click)="searchInput.value = ''">Clear</button>

    <!-- Read the value with interpolation -->
    <p>Query: {{ searchInput.value }}</p>

    <!-- ── Reference a child component ─────────────────────── -->
    <!-- <app-counter #counter />
         <button (click)="counter.reset()">Reset counter</button> -->
    <!-- #counter gives you the CounterComponent instance,
         letting you call its methods directly from the template -->

    <!-- ── Reference a form ─────────────────────────────────── -->
    <form #loginForm="ngForm" (submit)="onSubmit(loginForm.value)">
      <input name="email"    ngModel type="email"    placeholder="Email" />
      <input name="password" ngModel type="password" placeholder="Password" />
      <button [disabled]="loginForm.invalid">Login</button>
      <p>Valid: {{ loginForm.valid }}</p>
    </form>
  `,
})
export class TemplateRefDemoComponent {
  search(query: string): void {
    console.log('Searching for:', query);
  }

  onSubmit(value: { email: string; password: string }): void {
    console.log('Form value:', value);
  }
}

import { Component, signal, computed } from '@angular/core';
import { FormsModule } from '@angular/forms';

const ITEMS = ['Angular', 'React', 'Vue', 'Svelte', 'Next.js', 'Nuxt', 'Astro'];

@Component({
  selector: 'app-search',
  standalone: true,
  imports: [FormsModule],
  template: `
    <div class="search-wrapper">

      <!-- ① Interpolation -->
      <h2>Found {{ results().length }} of {{ total }} frameworks</h2>

      <!-- ④ Two-way binding — #searchBox is a template ref variable -->
      <input
        #searchBox
        [(ngModel)]="query"
        (keydown.escape)="query = ''; searchBox.blur()"
        placeholder="Search frameworks..."
      />

      <!-- ② Property + ③ Event binding -->
      <button
        [disabled]="!query"
        (click)="query = ''"
      >
        Clear
      </button>

      <!-- Class binding for active filter -->
      <button
        [class.active]="onlyPopular()"
        (click)="onlyPopular.update(v => !v)"
      >
        Popular only
      </button>

      <!-- ② Property binding: hide list when empty query -->
      <ul [hidden]="!query">
        @for (item of results(); track item) {
          <li>{{ item }}</li>        <!-- ① Interpolation -->
        }
      </ul>

    </div>
  `,
})
export class SearchComponent {
  query       = '';               // used with [(ngModel)]
  onlyPopular = signal(false);
  total       = ITEMS.length;

  results = computed(() => {
    const q = this.query.toLowerCase();
    return ITEMS.filter(item => item.toLowerCase().includes(q));
  });
}
